args.sparql:
SELECT ?material ?materialLabel ?densityValue
WHERE {
  ?material wdt:P1187 ?density.
  ?density wikibase:quantityAmount ?densityValue.
  FILTER (datatype(?densityValue) = xsd:float).
  OPTIONAL { ?material rdfs:label ?materialLabel. FILTER (lang(?materialLabel) = "en") }
}
ORDER BY DESC(?densityValue)
LIMIT 1

